import React from "react";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "cloud"; // Replace with real-time data
  const isDaytime = true; // Replace with logic from API or current time

  return (
    <div className="relative flex flex-col min-h-screen overflow-hidden bg-white dark:bg-black">
      {/* Background GIF overlay */}
      <WeatherOverlay weatherCondition={weatherCondition} isDaytime={isDaytime} />

      {/* Header */}
      <div className="text-center py-6 z-10">
        <h1 className="text-4xl font-bold text-gray-800 dark:text-white drop-shadow-md">
          Today in <span className="text-purple-500">Atlanta</span>
        </h1>
        <p className="text-lg text-gray-600 dark:text-white/80 mt-1 capitalize drop-shadow-md">
          {weatherCondition}
        </p>
      </div>

      {/* Weather Cards (Restored to Original Style) */}
      <div className="flex-1 flex items-center justify-center px-6 z-10 pb-24">
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6">
          {[
            { label: "Temperature", value: "36.2°C" },
            { label: "Humidity", value: "70%" },
            { label: "Wind Speed", value: "12 km/h" },
            { label: "UV Index", value: "5 (Moderate)" },
          ].map((card, idx) => (
            <div
              key={idx}
              className="transition-all duration-300 transform hover:scale-105 hover:shadow-2xl hover:bg-purple-200/40 bg-white/60 backdrop-blur-md rounded-xl shadow-md p-6"
            >
              <p className="text-md font-medium text-gray-600">{card.label}</p>
              <p className="text-3xl font-bold text-gray-800 mt-2">{card.value}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom Navigation */}
      <div className="h-20 fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/40 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-gray-700 hover:text-purple-500 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
